import{_ as s,o as a,c as e,af as o}from"./chunks/framework.DZTH9Z-c.js";const h=JSON.parse('{"title":"Архитектура платформы","description":"Детальное описание архитектуры Coreness. Event-driven система, плагины, DI контейнер, мультитенантность и структура проекта.","frontmatter":{"title":"Архитектура платформы","description":"Детальное описание архитектуры Coreness. Event-driven система, плагины, DI контейнер, мультитенантность и структура проекта.","keywords":"архитектура coreness, event-driven, dependency injection, плагины, мультитенантность","head":[["meta",{"property":"og:title","content":"Архитектура платформы | Coreness"}],["meta",{"property":"og:description","content":"Детальное описание архитектуры Coreness. Event-driven система, плагины, DI контейнер, мультитенантность и структура проекта."}],["meta",{"property":"og:image","content":"https://docs.coreness.tech/logo-dark.png"}],["meta",{"property":"og:url","content":"https://docs.coreness.tech/advanced/ARCHITECTURE"}],["link",{"rel":"canonical","href":"https://docs.coreness.tech/advanced/ARCHITECTURE"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Архитектура платформы\\",\\"description\\":\\"Детальное описание архитектуры Coreness. Event-driven система, плагины, DI контейнер, мультитенантность и структура проекта.\\",\\"url\\":\\"https://docs.coreness.tech/advanced/ARCHITECTURE\\"}"]]},"headers":[],"relativePath":"advanced/ARCHITECTURE.md","filePath":"advanced/ARCHITECTURE.md"}'),t={name:"advanced/ARCHITECTURE.md"};function i(r,n,l,p,c,g){return a(),e("div",null,[...n[0]||(n[0]=[o(`<h1 id="архитектура-проекта" tabindex="-1">Архитектура проекта <a class="header-anchor" href="#архитектура-проекта" aria-label="Permalink to &quot;Архитектура проекта&quot;">​</a></h1><h2 id="⚠️-требования-к-системе" tabindex="-1">⚠️ Требования к системе <a class="header-anchor" href="#⚠️-требования-к-системе" aria-label="Permalink to &quot;⚠️ Требования к системе&quot;">​</a></h2><h3 id="версия-python" tabindex="-1">Версия Python <a class="header-anchor" href="#версия-python" aria-label="Permalink to &quot;Версия Python&quot;">​</a></h3><ul><li><strong>✅ Рекомендуется:</strong> Python 3.11</li><li><strong>❌ Не рекомендуется:</strong> Python 3.12+ (может работать некорректно или не работать вовсе)</li><li><strong>ℹ️ Причина:</strong> Зависимости от специфичных версий библиотек и API</li></ul><h2 id="используемые-библиотеки" tabindex="-1">Используемые библиотеки <a class="header-anchor" href="#используемые-библиотеки" aria-label="Permalink to &quot;Используемые библиотеки&quot;">​</a></h2><ul><li><strong>SQLAlchemy</strong> — ORM для работы с базой данных</li><li><strong>PyYAML</strong> — парсинг YAML-конфигов</li><li><strong>psycopg2-binary</strong> — драйвер для подключения к PostgreSQL</li><li><strong>python-dotenv</strong> — загрузка переменных окружения</li><li><strong>unidecode</strong> — транслитерация</li><li><strong>emoji</strong> — поддержка emoji</li><li><strong>requests</strong> — HTTP-клиент для внешних API-запросов (tools, dev)</li><li><strong>aiohttp</strong> — асинхронный HTTP-клиент для Telegram Bot API</li><li><strong>openai</strong> — библиотека для работы с OpenAI API через OpenRouter</li><li><strong>gitpython</strong> — работа с Git репозиториями (деплой, обновления)</li><li><strong>telegramify-markdown</strong> — конвертация Markdown в Telegram MarkdownV2 формат</li><li><strong>croniter</strong> — парсинг и работа с cron выражениями для scheduled сценариев</li><li><strong>pydantic</strong> — валидация данных по схемам из config.yaml</li><li><strong>cryptography</strong> — генерация самоподписанных SSL-сертификатов для Telegram вебхуков</li><li><strong>pgvector</strong> — работа с векторными данными в PostgreSQL для RAG (Retrieval-Augmented Generation)</li><li><strong>python-dateutil</strong> — работа с датами и временными интервалами (корректная обработка месяцев/годов, края месяцев)</li></ul><h3 id="зависимости-для-системы-деплоя" tabindex="-1">Зависимости для системы деплоя <a class="header-anchor" href="#зависимости-для-системы-деплоя" aria-label="Permalink to &quot;Зависимости для системы деплоя&quot;">​</a></h3><p>Утилита деплоя (<code>tools/deployment/</code>) использует дополнительные библиотеки:</p><ul><li><strong>gitpython</strong> — клонирование репозиториев, работа с Git операциями</li><li><strong>requests</strong> — взаимодействие с GitHub API для создания Merge Requests</li><li><strong>PyYAML</strong> — парсинг конфигурации деплоя (<code>config.yaml</code>)</li><li><strong>python-dotenv</strong> — загрузка переменных окружения (токены, ключи API)</li></ul><h2 id="операционная-база-данных" tabindex="-1">Операционная база данных <a class="header-anchor" href="#операционная-база-данных" aria-label="Permalink to &quot;Операционная база данных&quot;">​</a></h2><p>Проект поддерживает <strong>две базы данных</strong> с возможностью переключения через пресеты:</p><ul><li><strong>SQLite</strong> — локальная база для небольших проектов (простота настройки)</li><li><strong>PostgreSQL</strong> — промышленная база для продакшна (высокая производительность, масштабируемость)</li></ul><h2 id="основные-принципы" tabindex="-1">Основные принципы <a class="header-anchor" href="#основные-принципы" aria-label="Permalink to &quot;Основные принципы&quot;">​</a></h2><ul><li><strong>Микросервисная архитектура</strong>: каждый сервис работает независимо и самодостаточно</li><li><strong>Event Driven Architecture</strong>: все действия инициируются событиями, обрабатываются оркестратором</li><li><strong>Vertical Slice Architecture</strong>: каждый сервис независим, получает только нужные данные, не зависит от других сервисов</li><li><strong>Конфигурируемость</strong>: вся логика и маршрутизация вынесена в yaml-конфиги</li><li><strong>Слоистая изоляция</strong>: четкое разделение ответственности между слоями с иерархией зависимостей</li><li><strong>Взаимодействие между сервисами</strong> — только через БД, за исключением редких случаев, когда сервис предоставляет публичные методы (API) для интеграции или специальных задач</li></ul><h2 id="слои-и-их-назначение" tabindex="-1">Слои и их назначение <a class="header-anchor" href="#слои-и-их-назначение" aria-label="Permalink to &quot;Слои и их назначение&quot;">​</a></h2><h3 id="foundation-foundation-—-фундаментальные-утилиты" tabindex="-1"><strong>Foundation (foundation)</strong> — Фундаментальные утилиты <a class="header-anchor" href="#foundation-foundation-—-фундаментальные-утилиты" aria-label="Permalink to &quot;**Foundation (foundation)** — Фундаментальные утилиты&quot;">​</a></h3><ul><li><strong>Назначение:</strong> Критически важные утилиты, без которых невозможно создать DI-контейнер и запустить приложение.</li><li><strong>Расположение:</strong> <code>plugins/utilities/foundation/</code></li><li><strong>Может использовать:</strong> Только системные библиотеки Python.</li></ul><h3 id="custom-layers-—-тематические-слои-утилит" tabindex="-1"><strong>Custom Layers</strong> — Тематические слои утилит <a class="header-anchor" href="#custom-layers-—-тематические-слои-утилит" aria-label="Permalink to &quot;**Custom Layers** — Тематические слои утилит&quot;">​</a></h3><ul><li><strong>Назначение:</strong> Утилиты для конкретных технологий или платформ (Telegram, API, базы данных и др.).</li><li><strong>Расположение:</strong> <code>plugins/utilities/[layer_name]/</code> (например, <code>telegram/</code>, <code>ai/</code>, <code>database/</code>)</li><li><strong>Может использовать:</strong> Foundation и утилиты внутри своего слоя (не рекомендуется использование из других custom-слоев).</li></ul><h3 id="core-core-—-инфраструктурные-утилиты" tabindex="-1"><strong>Core (core)</strong> — Инфраструктурные утилиты <a class="header-anchor" href="#core-core-—-инфраструктурные-утилиты" aria-label="Permalink to &quot;**Core (core)** — Инфраструктурные утилиты&quot;">​</a></h3><ul><li><strong>Назначение:</strong> Утилиты для создания и обработки событий, записи в очередь БД, работы с базой данных. Самый высокий уровень утилит.</li><li><strong>Расположение:</strong> <code>plugins/utilities/core/</code></li><li><strong>Может использовать:</strong> Foundation, custom-слои и другие core-утилиты.</li></ul><h3 id="services-services-—-бизнес-сервисы" tabindex="-1"><strong>Services (services)</strong> — Бизнес-сервисы <a class="header-anchor" href="#services-services-—-бизнес-сервисы" aria-label="Permalink to &quot;**Services (services)** — Бизнес-сервисы&quot;">​</a></h3><ul><li><strong>Назначение:</strong> Основная бизнес-логика приложения, плагины с конкретным функционалом.</li><li><strong>Расположение:</strong> <code>plugins/services/</code></li><li><strong>Может использовать:</strong> Foundation, custom-слои и core-утилиты.</li></ul><p>📋 <strong>Практические примеры использования слоев:</strong> <a href="./PLUGINS_GUIDE#практические-примеры-использования-слоев">Руководство по плагинам</a></p><h2 id="иерархия-зависимостеи" tabindex="-1">Иерархия зависимостей <a class="header-anchor" href="#иерархия-зависимостеи" aria-label="Permalink to &quot;Иерархия зависимостей&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Foundation (logger, plugins_manager, settings_manager)</span></span>
<span class="line"><span>    ↑</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Custom Layers  │</span></span>
<span class="line"><span>│ (telegram, etc) │</span></span>
<span class="line"><span>└─────────────────┘</span></span>
<span class="line"><span>    ↑</span></span>
<span class="line"><span>┌────────┐</span></span>
<span class="line"><span>│  Core  │</span></span>
<span class="line"><span>│  ───&gt;  │</span></span>
<span class="line"><span>└────────┘</span></span>
<span class="line"><span>    ↑</span></span>
<span class="line"><span>Services</span></span></code></pre></div><h3 id="правила-зависимостеи" tabindex="-1">Правила зависимостей <a class="header-anchor" href="#правила-зависимостеи" aria-label="Permalink to &quot;Правила зависимостей&quot;">​</a></h3><ol><li><strong>Foundation</strong> — используют только системные библиотеки Python</li><li><strong>Custom Layers</strong> — используют foundation и утилиты внутри своего слоя (не рекомендуется использование из других custom-слоев)</li><li><strong>Core</strong> — используют foundation, custom-слои и другие core-утилиты</li><li><strong>Services</strong> — используют foundation, custom-слои и core-утилиты</li><li><strong>Циклические зависимости</strong> <strong>ЗАПРЕЩЕНЫ</strong></li></ol><p>📋 <strong>Примеры зависимостей и практические рекомендации:</strong> <a href="./PLUGINS_GUIDE#система-зависимостей">Руководство по плагинам</a></p><h2 id="структура-директории" tabindex="-1">Структура директорий <a class="header-anchor" href="#структура-директории" aria-label="Permalink to &quot;Структура директорий&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app/                    # Основное приложение</span></span>
<span class="line"><span>├── application.py      # Точка входа и оркестратор</span></span>
<span class="line"><span>└── di_container.py     # Контейнер зависимостей</span></span>
<span class="line"><span></span></span>
<span class="line"><span>plugins/                # Плагины (утилиты и сервисы)</span></span>
<span class="line"><span>├── utilities/          # Вспомогательные слои утилит</span></span>
<span class="line"><span>│   ├── foundation/     # Фундаментальные утилиты (logger, plugins_manager)</span></span>
<span class="line"><span>│   ├── telegram/       # Telegram утилиты (tg_bot_api, tg_utils)</span></span>
<span class="line"><span>│   ├── ai/             # ИИ утилиты (ai_client)</span></span>
<span class="line"><span>│   └── core/           # Core утилиты (event_processor, database_service)</span></span>
<span class="line"><span>└── services/           # Бизнес-сервисы (плагины)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>utils/                  # Системные утилиты</span></span>
<span class="line"><span>├── database/           # Утилиты для работы с БД (миграции, обновления)</span></span>
<span class="line"><span>├── updater/            # Утилиты обновления ядра</span></span>
<span class="line"><span>└── ...                 # Другие системные утилиты</span></span>
<span class="line"><span></span></span>
<span class="line"><span>config/                 # Бизнес-конфигурация</span></span>
<span class="line"><span>└── settings.yaml       # Глобальные настройки системы</span></span></code></pre></div><p>📋 <strong>Правила создания плагинов и структура папок:</strong> <a href="./PLUGINS_GUIDE#правила-создания-плагинов">Руководство по плагинам</a></p><h2 id="поток-обработки" tabindex="-1">Поток обработки <a class="header-anchor" href="#поток-обработки" aria-label="Permalink to &quot;Поток обработки&quot;">​</a></h2><ol><li><strong>Application</strong> (<code>app/application.py</code>) инициализирует foundation утилиты (logger, plugins_manager), собирает информацию обо всех плагинах, регистрирует их, создает контейнер зависимостей и запускает все сервисы.</li><li><strong>Core</strong> утилиты (<code>plugins/utilities/core/</code>) принимают события от внешних источников (например, Telegram Bot API через HTTP, внешние сервисы), обрабатывают их и передают в оркестратор.</li><li><strong>Оркестратор</strong> анализирует события, находит подходящие сценарии и создает задачи для выполнения.</li><li><strong>Services</strong> (<code>plugins/services/</code>) выполняют бизнес-логику через вызовы методов ядра.</li><li><strong>Взаимодействие между сервисами</strong> — только через БД.</li></ol><p>📋 <strong>Алгоритм инициализации и порядок загрузки:</strong> <a href="./PLUGINS_GUIDE#инициализация-и-порядок-загрузки">Руководство по плагинам</a></p>`,35)])])}const u=s(t,[["render",i]]);export{h as __pageData,u as default};
